class Solution:
    def stringSequence(self, target):
        screen = ""
        result = []
        for ch in target:
            screen += "a"
            result.append(screen)
            while screen[-1] != ch:
                screen = screen[:-1] + chr(ord(screen[-1]) + 1)
                result.append(screen)
        return result

