class Solution:
    def stringSequence(self, target):
        result = []
        current = []
        for ch in target:
            current.append('a')
            result.append(''.join(current))
            steps = ord(ch) - ord('a')
            for _ in range(steps):
                current[-1] = chr(ord(current[-1]) + 1)
                result.append(''.join(current))
        return result

